define([],function(){"use strict";var initialized=false,state=new WeakMap();function getStep(c){var card=c.querySelector(".carrousel-card-item");if(!card)return 216;var gap=parseFloat(window.getComputedStyle(c).gap)||16;return card.offsetWidth+gap;}function getVisibleCount(c){var card=c.querySelector(".carrousel-card-item");if(!card)return 3;var step=card.offsetWidth+(parseFloat(window.getComputedStyle(c).gap)||16);var w=c.closest(".carrousel-nav-wrapper").clientWidth;return Math.max(1,Math.floor(w/step));}function getTotalCards(c){return c.querySelectorAll(".carrousel-card-item").length;}function applyTransform(c,idx){c.style.transform="translateX(-"+(idx*getStep(c))+"px)";}function init(){if(initialized)return;initialized=true;document.addEventListener("click",function(e){var btn=e.target.closest(".carrousel-prev-btn,.carrousel-next-btn");if(!btn)return;var wrapper=btn.closest(".carrousel-nav-wrapper");if(!wrapper)return;var container=wrapper.querySelector(".carrousel-scroll-container");if(!container)return;if(!state.has(wrapper))state.set(wrapper,{index:0});var s=state.get(wrapper);var max=Math.max(0,getTotalCards(container)-getVisibleCount(container));if(btn.classList.contains("carrousel-prev-btn")){s.index=Math.max(0,s.index-1);}else{s.index=Math.min(max,s.index+1);}applyTransform(container,s.index);});}return{init:init};});
